  html += '    function loadTemplates() { var token = localStorage.getItem(\'token\'); if (!token) return; fetch(API_BASE + \'/api/chef/profile/templates\', { headers: { \'Authorization\': \'Bearer \' + token } }).then(function(r) { return r.ok ? r.json() : null; }).then(function(data) { if (data && data.templates && data.templates.length > 0) { currentTemplates = data.templates; } }).catch(function() {}); }\n';
  html += '    function interpolateTemplate(text, lead) { if (!text) return \'\'; return text.replace(/\\{\\{diner_name\\}\\}/g, lead.clientName || \'there\').replace(/\\{\\{date\\}\\}/g, lead.eventDate || \'TBD\').replace(/\\{\\{time\\}\\}/g, lead.eventTime || \'\').replace(/\\{\\{party_size\\}\\}/g, String(lead.guestCount || 0)).replace(/\\{\\{proposed_menu\\}\\}/g, lead.serviceName || \'\').replace(/\\{\\{chef_name\\}\\}/g, lead.chefName || \'\'); }\n';
  html += '    function applyTemplate(templateId) { var tmpl = currentTemplates.find(function(t) { return t.id === templateId; }); if (!tmpl) return; var msgEl = document.getElementById(\'quoteMessage\'); if (!msgEl) return; var interpolated = interpolateTemplate(tmpl.text, currentLeadData || {}); if (msgEl.value.trim().length === 0) { msgEl.value = interpolated; } else { msgEl.value = msgEl.value.trim() + \'\\n\\n\' + interpolated; } msgEl.focus(); }\n';
  html += '    function injectTemplatePicker() { var quoteSection = document.querySelector(\'.quote-section\'); if (!quoteSection) return; if (document.getElementById(\'templatePicker\')) return; var picker = document.createElement(\'div\'); picker.id = \'templatePicker\'; picker.className = \'template-picker\'; var label = document.createElement(\'div\'); label.className = \'template-picker-label\'; label.textContent = \'Quick-Reply Templates\'; picker.appendChild(label); var buttons = document.createElement(\'div\'); buttons.className = \'template-buttons\'; for (var i = 0; i < currentTemplates.length; i++) { var tmpl = currentTemplates[i]; var btn = document.createElement(\'button\'); btn.className = \'template-btn\'; btn.textContent = tmpl.label; btn.title = tmpl.text.replace(/\\n/g, \' \').substring(0, 60) + \'...\'; btn.onclick = function(id) { return function() { applyTemplate(id); }; }(tmpl.id); buttons.appendChild(btn); } picker.appendChild(buttons); var firstFormGroup = quoteSection.querySelector(\'.form-group\'); if (firstFormGroup) { quoteSection.insertBefore(picker, firstFormGroup); } else { quoteSection.appendChild(picker); } }\n';

  html += '    var tutorialDismissed = false;\n';
